1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // --- Simplest cases ---
6	  it("empty item list → premium 5 G (only processing fee)", () => {
7	    const out = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(out).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // --- Base premiums per main item type (no modifiers, 0 years, first quote) ---
15	  // Plain item base premium + 10 G first-insurance + 5 G fee
16	  it("plain sword (steel, enchantment 0) for new customer → premium 115 G (100 + 10 + 5)", () => {
17	    const out = runScenario({
18	      customer: { yearsWithMHPCO: 0 },
19	      steps: [
20	        {
21	          op: "quote",
22	          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
23	        },
24	      ],
25	    });
26	    expect(out).toEqual({ results: [{ premium: 115 }] });
27	  });
28	  it("plain amulet for new customer → premium 71 G (60 + 6 first-insurance rounded up + 5)", () => {
29	    const out = runScenario({
30	      customer: { yearsWithMHPCO: 0 },
31	      steps: [
32	        {
33	          op: "quote",
34	          items: [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }],
35	        },
36	      ],
37	    });
38	    expect(out).toEqual({ results: [{ premium: 71 }] });
39	  });
40	  it.todo("plain staff for new customer → premium 93 G (80 + 8 + 5)");
41	  it.todo("plain potion for new customer → premium 49 G (40 + 4 + 5)");
42	
43	  // --- Component pricing (runes/moonstones) ---
44	  it.todo("2 runes → base premium 50 G (no block)");
45	  it.todo("3 runes → base premium 60 G (block applies)");
46	  it.todo("4 runes → base premium 100 G (no block — block requires exactly 3)");
47	  it.todo("7 runes → base premium 175 G (3-block + 4 leftover at 25 G each)");
48	
49	  // --- 'Alike' components clarification (❓) ---
50	  it.todo("2 runes + 1 moonstone → base premium 75 G (no block: different types)");
51	  it.todo("3 runes + 3 moonstones → base premium 120 G (two separate blocks)");
52	
53	  // --- Modifiers in isolation (item-specific) ---
54	  it.todo("newcomer with a cursed sword (steel, enchantment 3) → premium 165 G");
55	  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies (130 G + 5 fee + 13 first ins.)");
56	  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
57	  it.todo("cursed sword with exactly enchantment 5 → both surcharges apply");
58	
59	  // --- Policy-wide modifiers ---
60	  it.todo("customer with exactly 2 years with MHPCO → loyalty discount applies");
61	  it.todo("first quote in scenario carries 10% first-insurance surcharge per item");
62	  it.todo("second quote in scenario gets 15% follow-up contract discount");
63	
64	  // --- Modifier scope on multi-item policies (❓) ---
65	  it.todo("cursed sword + plain amulet → 210 G before fee (item-specific surcharge applies only to cursed item)");
66	
67	  // --- Rounding in MHPCO's favor ---
68	  it.todo("premium calculation yielding 197.5 G → final premium 198 G (rounded up)");
69	  it.todo("payout calculation yielding 350.5 G → final payout 350 G (rounded down)");
70	  it.todo("intermediate amounts kept as fractions; only final is rounded");
71	
72	  // --- Integration examples ---
73	  it.todo("newcomer with cursed sword (steel, enchantment 3) → premium 165 G");
74	  it.todo("long-standing customer's second contract (3 years, cursed sword enchantment 7) → premium 160 G");
75	
76	  // --- Claim processing: standard reimbursement ---
77	  it.todo("regular sword (steel, enchantment 3), damage 500 G → payout 400 G (500 - 100 deductible)");
78	  it.todo("damage to a rune (value 250 G), damage 200 G → payout 100 G");
79	
80	  // --- Claim processing: enchantment threshold ---
81	  it.todo("dragon-material sword with exactly enchantment 8, damage 1000 G → payout 400 G (high-ench wins, then deductible)");
82	  it.todo("dragon-material sword, enchantment 9, damage 1000 G → payout 400 G (50% then deductible)");
83	  it.todo("dragon-material sword, enchantment 5, damage 800 G → payout 700 G (dragon only: full minus deductible)");
84	  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (high-ench: 50% then deductible)");
85	
86	  // --- Deductible per damage event ---
87	  it.todo("dragon attack damages sword (500 G) and amulet (300 G) → payout 600 G (deductible once per damaged item)");
88	
89	  // --- Multiple items of same type ---
90	  it.todo("policy covers two swords → insurance sum 2000 G, cap 4000 G");
91	  it.todo("two-sword policy: dragon attack with two sword damage entries → each treated separately with own deductible");
92	  it.todo("damages contain more entries of a type than policy covers → CLI exits non-zero");
93	
94	  // --- Cap exhaustion ---
95	  it.todo("policy covers sword + amulet → insurance sum 1600 G, cap 3200 G");
96	  it.todo("cursed sword (insurance value 1000 G) → cap 2000 G (modifiers do not raise cap)");
97	  it.todo("policy with sword + 3 runes → insurance sum 1750 G (block discount affects premium only)");
98	  it.todo("sword insured (cap 2000 G); two successive 1500 G claims → first 1400 G remaining 600 G; second 600 G remaining 0 G");
99	
100	  // --- Edge cases ---
101	  it.todo("quote includes unknown item type (e.g. 'broomstick') → CLI exits non-zero with stderr error, no results on stdout");
102	  it.todo("claim references damage entry whose item is not part of the policy → CLI exits non-zero with stderr error");
103	  it.todo("claim references damage entry with unknown item type → CLI exits non-zero with stderr error");
104	  it.todo("claim contains damage entry with negative amount → CLI exits non-zero with stderr error");
105	
106	  // --- End-to-end schema example ---
107	  it.todo("schema example: long-standing customer amulet quote + fire claim 200 G → premium and payout integers per schema");
108	});
109

1	export type Item = {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	};
7	
8	export type QuoteStep = { op: "quote"; items: Item[] };
9	export type Step = QuoteStep;
10	
11	export type Scenario = {
12	  customer: { yearsWithMHPCO: number };
13	  steps: Step[];
14	};
15	
16	export type QuoteResult = { premium: number };
17	export type StepResult = QuoteResult;
18	export type ScenarioResult = { results: StepResult[] };
19	
20	const PROCESSING_FEE = 5;
21	// Surcharge expressed in tenths of base premium to keep arithmetic in integers
22	// until the final rounding step (avoids 100 * 1.1 = 110.00000000000001).
23	const FIRST_INSURANCE_TENTHS = 1;
24	
25	const basePremium = (item: Item): number => {
26	  if (item.type === "sword") return 100;
27	  if (item.type === "amulet") return 60;
28	  return 0;
29	};
30	
31	const itemPremiumTenths = (item: Item): number =>
32	  basePremium(item) * (10 + FIRST_INSURANCE_TENTHS);
33	
34	const quote = (step: QuoteStep): QuoteResult => {
35	  const itemsTotalTenths = step.items.reduce((sum, item) => sum + itemPremiumTenths(item), 0);
36	  return { premium: Math.ceil(itemsTotalTenths / 10) + PROCESSING_FEE };
37	};
38	
39	export const runScenario = (scenario: Scenario): ScenarioResult => {
40	  return { results: scenario.steps.map(quote) };
41	};
